const staticData = $getWorkflowStaticData('global');
if (!staticData.textedNumbers) staticData.textedNumbers = {};

const phone = $json.body.phone;
const now = Date.now();
const twoHoursMs = 2 * 60 * 60 * 1000;
const lastTexted = staticData.textedNumbers[phone];
const isDuplicate = Boolean(lastTexted) && (now - lastTexted) < twoHoursMs;

return [{
  json: {
    ...$json.body,
    isDuplicate,
    lastTextedAt: lastTexted || null,
    hoursSinceLastText: lastTexted ? Math.round((now - lastTexted) / 3600000 * 100) / 100 : null
  }
}];

const staticData = $getWorkflowStaticData("global");
if (!staticData.textedNumbers) staticData.textedNumbers = {};

let phone, contactId;
try { phone = $("Compose Message: New Lead").item.json.phone; contactId = $("Compose Message: New Lead").item.json.contactId; } catch (e) {}
if (!phone) {
  try { phone = $("Compose Message: Repeat Customer").item.json.phone; contactId = $("Compose Message: Repeat Customer").item.json.contactId; } catch (e) {}
}

staticData.textedNumbers[phone] = Date.now();
return [{ json: { ...$json, phone, contactId, textedAt: new Date().toISOString() } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.failureLog) staticData.failureLog = [];
const entry = { at: new Date().toISOString(), data: $json };
staticData.failureLog.push(entry);
console.log('Missed-call textback FAILED, logging for manual follow-up:', JSON.stringify(entry));
return [{ json: { ...$json, loggedForManualFollowUp: true } }];

